def gen(rng, size):
    entities = ['&quot;', '&apos;', '&amp;', '&gt;', '&lt;', '&frasl;']
    parts = []
    for _ in range(size):
        if rng.random() < 0.4:
            parts.append(rng.choice(entities))
        else:
            parts.append(rng.choice('abcdefghijklmnopqrstuvwxyz '))
    return [''.join(parts)]

