class Solution:
    def entityParser(self, text: str) -> str:
        mapping = {'&quot;': '"', '&apos;': "'", '&amp;': '&', '&gt;': '>', '&lt;': '<', '&frasl;': '/'}
        result = []
        i = 0
        while i < len(text):
            matched = False
            if text[i] == '&':
                for entity, char in mapping.items():
                    if text[i:i+len(entity)] == entity:
                        result.append(char)
                        i += len(entity)
                        matched = True
                        break
            if not matched:
                result.append(text[i])
                i += 1
        return ''.join(result)

