class Solution:
    def entityParser(self, text: str) -> str:
        import re
        mapping = {'&quot;': '"', '&apos;': "'", '&amp;': '&', '&gt;': '>', '&lt;': '<', '&frasl;': '/'}
        pattern = re.compile('|'.join(re.escape(k) for k in mapping))
        return pattern.sub(lambda m: mapping[m.group(0)], text)

